/**
	 * Builds an array of line items/totals to be sent back to Square in the lineItems array.
	 *
	 * @since 2.3
	 * @param array $totals
	 * @return array
	 */
function build_payment_request_line_items( $totals = array() ) {
		// Ignoring nonce verification checks as it is already handled in the parent function.
		$totals     = empty( $totals ) ? $this->get_cart_totals() : $totals;
		$line_items = array();
		$order_id   = isset( $_POST['order_id'] ) ? (int) sanitize_text_field( wp_unslash( $_POST['order_id'] ) ) : absint( get_query_var( 'order-pay' ) ); // phpcs:ignore WordPress.Security.NonceVerification.Missing
		$order_id   = Order_Ajax_Authorization::trusted_line_items_order_id( $order_id );

		if ( $order_id ) {
			$order    = wc_get_order( $order_id );
			$iterable = $order->get_items();
		} else {
			$iterable = WC()->cart->get_cart();
		}

		foreach ( $iterable as $item ) {
			$amount = number_format( $order_id ? $order->get_subtotal() : $item['line_subtotal'], 2, '.', '' );

			if ( $order_id ) {
				$quantity_label = 1 < $item->get_quantity() ? ' x ' . $item->get_quantity() : '';
			} else {
				$quantity_label = 1 < $item['quantity'] ? ' x ' . $item['quantity'] : '';
			}

			$item = array(
				'label'   => $order_id ? $item->get_name() . $quantity_label : $item['data']->get_name() . $quantity_label,
				'amount'  => $amount,
				'pending' => false,
			);

			$line_items[] = $item;
		}

		if ( $totals['shipping'] > 0 ) {
			$line_items[] = array(
				'label'   => __( 'Shipping', 'woocommerce-square' ),
				'amount'  => number_format( $totals['shipping'], 2, '.', '' ),
				'pending' => false,
			);
		}

		if ( $totals['taxes'] > 0 ) {
			$line_items[] = array(
				'label'   => __( 'Tax', 'woocommerce-square' ),
				'amount'  => number_format( $totals['taxes'], 2, '.', '' ),
				'pending' => false,
			);
		}

		if ( $totals['discount'] > 0 ) {
			$line_items[] = array(
				'label'   => __( 'Discount', 'woocommerce-square' ),
				'amount'  => number_format( $totals['discount'], 2, '.', '' ),
				'pending' => false,
			);
		}

		if ( $totals['fees'] > 0 ) {
			$line_items[] = array(
				'label'   => __( 'Fees', 'woocommerce-square' ),
				'amount'  => number_format( $totals['fees'], 2, '.', '' ),
				'pending' => false,
			);
		}

		return $line_items;
	}

/**
		 * Vault v2 Free trial subscription, adds vaulted PayPal email to localized script data.
		 */
function run( ContainerInterface $c ): bool {
		$subscriptions_helper = $c->get( 'wc-subscriptions.helper' );
		assert( $subscriptions_helper instanceof SubscriptionHelper );
		if ( ! $subscriptions_helper->plugin_is_active() ) {
			return true;
		}

		$this->add_gateways_support( $c );

		add_action(
			'woocommerce_scheduled_subscription_payment_' . PayPalGateway::ID,

			function ( $amount, $order ) use ( $c ) {
				$this->renew( $order, $c );
			},
			10,
			2
		);

		add_action(
			'woocommerce_scheduled_subscription_payment_' . CreditCardGateway::ID,

			function ( $amount, $order ) use ( $c ) {
				$this->renew( $order, $c );
			},
			10,
			2
		);

		add_filter(
			'woocommerce_subscription_payment_method_to_display',

			function ( $payment_method_to_display, $subscription, $context ) {
				$payment_gateway = wc_get_payment_gateway_by_order( $subscription );

				if ( $payment_gateway instanceof \WC_Payment_Gateway && $payment_gateway->id === PayPalGateway::ID ) {
					return $subscription->get_payment_method_title( $context );
				}

				return $payment_method_to_display;
			},
			10,
			3
		);

		add_action(
			'wc_ajax_' . SubscriptionChangePaymentMethod::ENDPOINT,
			static function () use ( $c ) {
				$endpoint = $c->get( 'wc-subscriptions.endpoint.subscription-change-payment-method' );
				assert( $endpoint instanceof SubscriptionChangePaymentMethod );

				$endpoint->handle_request();
			}
		);

		add_action(
			'woocommerce_subscriptions_change_payment_after_submit',
			function () use ( $c ) {
				$context = $c->get( 'button.helper.context' );
				assert( $context instanceof Context );

				if ( ! is_user_logged_in() || ! $context->is_subscription_change_payment_method_page() ) {
					return;
				}

				$payment_method_tokens_checked = $c->get( 'save-payment-methods.service.payment-method-tokens-checker' );
				assert( $payment_method_tokens_checked instanceof PaymentMethodTokensChecker );
				$customer_id = get_user_meta( get_current_user_id(), '_ppcp_target_customer_id', true );

				// Do not display PayPal button if the user already has a PayPal payment token.
				if ( $payment_method_tokens_checked->has_paypal_payment_token( $customer_id ) ) {
					return;
				}

				echo '<div id="ppc-button-' . esc_attr( PayPalGateway::ID ) . '-save-payment-method"></div>';
			}
		);


		add_filter(
			'woocommerce_paypal_payments_before_order_process',

			function ( bool $process, $gateway, WC_Order $wc_order ) use ( $c ) {
				if ( ! $gateway instanceof PayPalGateway || $gateway::ID !== PayPalGateway::ID ) {
					return $process;
				}

				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					$change_payment_method = $c->get( 'wc-subscriptions.change-payment-method' );
					assert( $change_payment_method instanceof ChangePaymentMethod );

					return $change_payment_method->to_paypal_payment();
				}

				$change_payment_method_vault_v2 = $c->get( 'wc-subscriptions.vault-v2.change-payment-method' );
				assert( $change_payment_method_vault_v2 instanceof ChangePaymentMethodVaultV2 );

				try {
					return $change_payment_method_vault_v2->to_paypal_payment( $wc_order );
				} catch ( Exception $exception ) {
					throw new Exception( $exception->getMessage() );
				}
			},
			10,
			3
		);


		add_action(
			'woocommerce_subscription_payment_complete',

			function ( $subscription ) use ( $c ) {
				if ( ! in_array( $subscription->get_payment_method(), array( PayPalGateway::ID, CreditCardGateway::ID, CardButtonGateway::ID ), true ) ) {
					return;
				}

				$paypal_subscription_id = $subscription->get_meta( 'ppcp_subscription' ) ?? '';
				if ( $paypal_subscription_id ) {
					return;
				}

				$payment_token_repository = $c->get( 'vaulting.repository.payment-token' );
				$logger                   = $c->get( 'woocommerce.logger.woocommerce' );

				if ( ! $c->has( 'save-payment-methods.eligible' ) || ! $c->get( 'save-payment-methods.eligible' ) ) {
					$this->add_payment_token_id( $subscription, $payment_token_repository, $logger );
				}

				if ( count( $subscription->get_related_orders() ) === 1 ) {
					$parent_order = $subscription->get_parent();
					if ( $parent_order instanceof WC_Order ) {
						// Update the initial payment method title if not the same as the first order.
						$payment_method_title = $parent_order->get_payment_method_title();
						if (
							$payment_method_title
							&& $subscription instanceof \WC_Subscription
							&& $subscription->get_payment_method_title() !== $payment_method_title
						) {
							$subscription->set_payment_method_title( $payment_method_title );
							$subscription->save();
						}
					}
				}
			}
		);


		add_filter(
			'woocommerce_available_payment_gateways',

			function ( $methods ) use ( $c ) {
				if ( ! is_array( $methods ) ) {
					return $methods;
				}

				//phpcs:disable WordPress.Security.NonceVerification.Recommended
				if ( ! ( isset( $_GET['change_payment_method'] ) && is_wc_endpoint_url( 'order-pay' ) ) ) {
					return $methods;
				}

				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					return $methods;
				}

				// Vault v2 - If customer does not have saved PayPal payments, remove PayPal gateway from available payment methods.
				// The reason is that it's not possible to save a payment without purchasing.
				$paypal_tokens = WC_Payment_Tokens::get_customer_tokens( get_current_user_id(), PayPalGateway::ID );
				if ( ! $paypal_tokens ) {
					unset( $methods[ PayPalGateway::ID ] );
				}

				// Vault v2 - If customer does not have saved card payments, remove credit card gateway from available payment methods.
				// The reason is that it's not possible to save a payment without purchasing.
				$card_tokens = WC_Payment_Tokens::get_customer_tokens( get_current_user_id(), CreditCardGateway::ID );
				if ( ! $card_tokens ) {
					unset( $methods[ CreditCardGateway::ID ] );
				}

				return $methods;
			}
		);


		add_filter(
			'woocommerce_gateway_description',

			function ( $description, $id ) use ( $c ) {
				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					return $description;
				}

				$display_saved_payment_tokens = $c->get( 'wc-subscriptions.vault-v2.display-saved-payment-tokens' );
				assert( $display_saved_payment_tokens instanceof DisplaySavedPaymentTokens );

				return $display_saved_payment_tokens->display_saved_paypal_payments( (string) $id, (string) $description );
			},
			10,
			2
		);


		add_filter(
			'woocommerce_credit_card_form_fields',

			function ( $default_fields, $id ) use ( $c ) {
				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					return $default_fields;
				}

				$display_saved_payment_tokens = $c->get( 'wc-subscriptions.vault-v2.display-saved-payment-tokens' );
				assert( $display_saved_payment_tokens instanceof DisplaySavedPaymentTokens );

				return $display_saved_payment_tokens->display_saved_credit_cards( (string) $id, $default_fields );
			},
			20,
			2
		);


		add_action(
			'woocommerce_paypal_payments_smart_button_render_wrapper',
			function () use ( $c ) {
				// Return early if save payment methods (Vault v3) is enabled.
				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					return;
				}

				$free_trial_subscription_helper = $c->get( 'wc-subscriptions.free-trial-subscription-helper' );
				assert( $free_trial_subscription_helper instanceof FreeTrialSubscriptionHelper );

				if ( ! $free_trial_subscription_helper->is_free_trial_cart() ) {
					return;
				}

				add_action(
					'woocommerce_review_order_after_submit',
					function () use ( $c ) {
						$vaulted_paypal_email = $c->get( 'wc-subscriptions.vault-v2.vaulted-paypal-email' );
						assert( $vaulted_paypal_email instanceof VaultedPayPalEmail );

						$vaulted_email = $vaulted_paypal_email->get_vaulted_paypal_email();
						if ( ! $vaulted_email ) {
							return;
						}

						?>
						<div class="ppcp-vaulted-paypal-details">
							<?php
							echo wp_kses_post(
								sprintf(
								// translators: %1$s - email, %2$s, %3$s - HTML tags for a link.
									esc_html__(
										'Using %2$s%1$s%3$s PayPal.',
										'woocommerce-paypal-payments'
									),
									$vaulted_email,
									'<b>',
									'</b>'
								)
							);
							?>
						</div>
						<?php
					}
				);
			}
		);


		add_filter(
			'woocommerce_paypal_payments_localized_script_data',
			function ( array $localized_script_data ) use ( $c ) {
				if ( $c->has( 'save-payment-methods.eligible' ) && $c->get( 'save-payment-methods.eligible' ) ) {
					return $localized_script_data;
				}

				$free_trial_subscription_helper = $c->get( 'wc-subscriptions.free-trial-subscription-helper' );
				assert( $free_trial_subscription_helper instanceof FreeTrialSubscriptionHelper );

				if ( ! is_checkout() || ! $free_trial_subscription_helper->is_free_trial_cart() ) {
					return $localized_script_data;
				}

				$vaulted_paypal_email = $c->get( 'wc-subscriptions.vault-v2.vaulted-paypal-email' );
				assert( $vaulted_paypal_email instanceof VaultedPayPalEmail );

				$vaulted_email = $vaulted_paypal_email->get_vaulted_paypal_email();
				if ( $vaulted_email ) {
					$localized_script_data['vaulted_paypal_email'] = $vaulted_email;
				}

				return $localized_script_data;
			}
		);

		return true;
	}

/**
		 * Array of `true` values for each product IDs already handled by this method. Used to prevent double submission.
		 *
		 * @var bool[] $already_updated
		 */
function handle_update_product( WC_Product $product ) {

		static $already_updated = array();
		if ( isset( $already_updated[ $product->get_id() ] ) ) {
			return;
		}

		$form           = $this->get_form( $product );
		$form_view_data = $form->get_view_data();

		// phpcs:disable WordPress.Security.NonceVerification
		if ( empty( $_POST[ $form_view_data['name'] ] ) ) {
			return;
		}
		// phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized
		$submitted_data = (array) wc_clean( wp_unslash( $_POST[ $form_view_data['name'] ] ) );
		// phpcs:enable WordPress.Security.NonceVerification

		$form->submit( $submitted_data );
		$this->update_data( $product, $form->get_data() );

		$already_updated[ $product->get_id() ] = true;
	}

/**
			 * Auto login user
			 * Must set code below after Send email become a teacher
			 * because 'none' check by "check_ajax_referer" will not valid for send mail background on WP_Async_Request
			 */
function process_register() {
		if ( ! LP_Request::verify_nonce( 'learn-press-register' ) ) {
			return;
		}

		$username         = LP_Helper::sanitize_params_submitted( $_POST['reg_username'] ?? '' );
		$email            = LP_Helper::sanitize_params_submitted( $_POST['reg_email'] ?? '' );
		$password         = LP_Helper::sanitize_params_submitted( $_POST['reg_password'] ?? '' );
		$confirm_password = LP_Helper::sanitize_params_submitted( $_POST['reg_password2'] ?? '' );
		$first_name       = LP_Helper::sanitize_params_submitted( $_POST['reg_first_name'] ?? '' );
		$last_name        = LP_Helper::sanitize_params_submitted( $_POST['reg_last_name'] ?? '' );
		$display_name     = LP_Helper::sanitize_params_submitted( $_POST['reg_display_name'] ?? '' );
		$update_meta      = LP_Helper::sanitize_params_submitted( $_POST['_lp_custom_register_form'] ?? '' );

		try {
			$new_customer = self::learnpress_create_new_customer(
				sanitize_email( $email ),
				$username,
				$password,
				$confirm_password,
				array(
					'first_name'   => $first_name,
					'last_name'    => $last_name,
					'display_name' => $display_name,
				),
				$update_meta
			);

			if ( is_wp_error( $new_customer ) ) {
				throw new Exception( $new_customer->get_error_message() );
			}

			// Send email become a teacher.
			$is_become_a_teacher = false;
			if ( LP_Settings::get_option( 'instructor_registration', 'no' ) == 'yes' && isset( $_POST['become_teacher'] ) ) {
				update_user_meta( $new_customer, '_requested_become_teacher', 'yes' );
				do_action(
					'learn-press/become-a-teacher-sent',
					array(
						'bat_email'   => $email,
						'bat_phone'   => '',
						'bat_message' => apply_filters( 'learnpress_become_instructor_message', esc_html__( 'I need to become an instructor', 'learnpress' ) ),
					)
				);

				$is_become_a_teacher = true;
			}


			wp_set_current_user( $new_customer );
			wp_set_auth_cookie( $new_customer, true );

			$message_success = $username . __( ' was successfully created!', 'learnpress' );

			if ( $is_become_a_teacher ) {
				$message_success .= '<br/>' . __( 'Your request to become an instructor has been sent. We will get back to you soon!', 'learnpress' );
			}

			$message_data = [
				'status'  => 'success',
				'content' => $message_success,
			];
			learn_press_set_message( $message_data );

			if ( ! empty( $_POST['redirect'] ) ) {
				$url_redirect = wp_sanitize_redirect( wp_unslash( $_POST['redirect'] ) );
			} elseif ( ! empty( $_REQUEST['_wp_http_referer'] ) ) {
				$url_redirect = wp_unslash( $_REQUEST['_wp_http_referer'] );
			} else {
				$url_redirect = LP_Request::get_redirect( learn_press_get_page_link( 'profile' ) );
			}
			$url_redirect = apply_filters( 'learn-press/register-redirect', $url_redirect, $new_customer );
			wp_redirect( wp_validate_redirect( $url_redirect, LP_Helper::getUrlCurrent() ) );
			exit();

		} catch ( Throwable $e ) {
			$message_data = [
				'status'  => 'error',
				'content' => $e->getMessage(),
			];
			learn_press_set_message( $message_data );
		}
	}

/**
	 * Update section items.
	 *
	 * @param $section_id
	 * @param $items array
	 *
	 * @return array
	 * @since 3.0.1
	 */
function update_section_items( $section_id, $items ) {
		global $wpdb;

		foreach ( $items as $index => $item ) {
			$item_id   = 0;
			$item_type = '';
			if ( is_object( $item ) ) {
				$item_id   = $item->id ?? 0;
				$item_type = $item->post_type ?? '';
			} elseif ( is_array( $item ) ) {
				$item_id   = $item['id'] ?? 0;
				$item_type = $item['type'] ?? '';
			}

			$order = $index + 1;
			$exist = $this->item_section_exist( $section_id, $item_id );

			if ( $exist ) {
				$wpdb->update(
					$wpdb->learnpress_section_items,
					array( 'item_order' => $order ),
					array(
						'section_id' => $section_id,
						'item_id'    => $item_id,
					)
				);
			} else {
				$wpdb->insert(
					$wpdb->learnpress_section_items,
					array(
						'section_id' => $section_id,
						'item_id'    => $item_id,
						'item_order' => $order,
						'item_type'  => $item_type,
					)
				);
			}
		}

		return $items;
	}

